import{_ as e,o as t,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const o="/images/navi5.png?raw=true",u=JSON.parse('{"title":"5 访问数据库","description":"","frontmatter":{},"headers":[],"relativePath":"05/0.md","filePath":"05/0.md","lastUpdated":null}'),s={name:"05/0.md"};function i(n,a,d,_,p,h){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="_5-访问数据库" tabindex="-1">5 访问数据库 <a class="header-anchor" href="#_5-访问数据库" aria-label="Permalink to &quot;5 访问数据库&quot;">​</a></h1><p>对许多Web应用程序而言，数据库都是其核心所在。数据库几乎可以用来存储你想查询和修改的任何信息，比如用户信息、产品目录或者新闻列表等。</p><p>Go没有内置的驱动支持任何的数据库，但是Go定义了database/sql接口，用户可以基于驱动接口开发相应数据库的驱动，5.1小节里面介绍Go设计的一些驱动，介绍Go是如何设计数据库驱动接口的。5.2至5.4小节介绍目前使用的比较多的一些关系型数据驱动以及如何使用，5.5小节介绍我自己开发一个ORM库，基于database/sql标准接口开发的，可以兼容几乎所有支持database/sql的数据库驱动，可以方便的使用Go style来进行数据库操作。</p><p>目前NOSQL已经成为Web开发的一个潮流，很多应用采用了NOSQL作为数据库，而不是以前的缓存，5.6小节将介绍MongoDB和Redis两种NOSQL数据库。</p><blockquote><p><a href="http://go-database-sql.org/" target="_blank" rel="noreferrer">Go database/sql tutorial</a> 里提供了惯用的范例及详细的说明。</p></blockquote><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+o+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/04/6.html">第四章总结</a></li><li>下一节: <a href="/05/1.html">database/sql接口</a></li></ul>',9)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
